import React from "react";
import useSplitPaymentStore from "../useSplitPaymentStore";

function PlanScheduleItem({ item }) {
    if (item) {
        const { dueDate, dueAmt } = item
        return (<div>
            <div>{dueDate}</div>
            <div>{dueAmt}</div>
        </div>)
    }
}

function PlanSchedule() {
    const planSchedule = useSplitPaymentStore((s) => s.planSchedule)
    if (planSchedule) {
        return (
            planSchedule.map((item) => {
                <PlanScheduleItem key={item.id} item={item} />
            })
        )
    }
}

export default PlanSchedule
